import{_ as t,o as r,c as a,a2 as i}from"./chunks/framework.BOIfnwPZ.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/must-have.md","filePath":"implementation/must-have.md","lastUpdated":1780503433000}'),s={name:"implementation/must-have.md"};function n(o,e,c,h,d,l){return r(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="must-have-checking-in-torch-pipeline" tabindex="-1">Must Have Checking in TORCH Pipeline <a class="header-anchor" href="#must-have-checking-in-torch-pipeline" aria-label="Permalink to &quot;Must Have Checking in TORCH Pipeline&quot;">​</a></h2><p>The must have checking i.e. ensuring required elements are present is a crucial step to ensure that the extracted data meets the criteria defined in the Clinical Resource Transfer Definition Language (CRTDL). Required elements are defined in the CRTDL using a must have flag.</p><p>Must Have checking is performed after resources are loaded from the FHIR server and during the reference resolve step.</p><p>Must have conditions can be violated in two ways:</p><ol><li>A resource is missing a required attribute as defined in the CRTDL.</li><li>A resource is missing a required reference to another resource as defined in the CRTDL.</li></ol><p>So the must-have checking is done in two steps:</p><h2 id="_1-field-must-have-check" tabindex="-1">1. <strong>Field Must Have Check</strong> <a class="header-anchor" href="#_1-field-must-have-check" aria-label="Permalink to &quot;1. **Field Must Have Check**&quot;">​</a></h2><p>Based on fhir path expressions, the must have check verifies that all required attributes specified in the CRTDL are filled in a resource. If any required attribute is missing, the extraction for that resource is stopped, and an error is logged.</p><h2 id="_2-reference-resolve" tabindex="-1">2. <strong>Reference Resolve</strong> <a class="header-anchor" href="#_2-reference-resolve" aria-label="Permalink to &quot;2. **Reference Resolve**&quot;">​</a></h2><p>The first must have check is done on the resources that are loaded directly from the FHIR server. In this step, references are only checked for existence, not for correctness.</p><p>A reference attribute in the CRTDL can be marked as must have and has a link to other attribute groups, that define the requirements for the referenced resource.</p><p>During <a href="./reference-resolve.html">Reference Resolve</a>, TORCH does the basic must have check on the resolved reference with the linked attribute groups. So not only does the reference need to be resolved, but the referenced resource also needs to pass the must have check for the linked attribute groups. If any must have condition is violated, the original referencing resource is considered to not fulfill its must have criteria and is marked for deletion and then cleaned up during the <a href="./cascading-delete.html">cascading delete</a> step.</p>',12)])])}const p=t(s,[["render",n]]);export{f as __pageData,p as default};
